import React, { useState, useEffect } from 'react';
import usePlayerStats from './usePlayerStats';

// Simple mock Firebase for now - we'll fix this properly later
const mockFirebaseData = [
  {
    id: 1,
    forename: 'Mason',
    surname: 'Burstow', 
    notes: 'Squad',
    goals: 12,
    league: 8,
    fACup: 2,
    eFLCup: 0,
    eFLTrophy: 2,
    rating: 8,
    currentWeeklyWage: 5000,
    overallTotal: 250000
  },
  {
    id: 2,
    forename: 'George',
    surname: 'Johnston',
    notes: 'Squad', 
    goals: 2,
    league: 1,
    fACup: 1,
    eFLCup: 0,
    eFLTrophy: 0,
    rating: 7,
    currentWeeklyWage: 3000,
    overallTotal: 150000
  }
];

const EnhancedSquadList = ({ isAuthenticated }) => {
  const [players, setPlayers] = useState([]);
  const [filteredPlayers, setFilteredPlayers] = useState([]);
  const [statusFilter, setStatusFilter] = useState('Squad');
  const [loading, setLoading] = useState(true);

  // Get dynamic player statistics
  const {
    playerStats,
    loading: statsLoading,
    error: statsError,
    getPlayerAppearanceSummary,
    getPlayerDisciplinarySummary,
    totalFixtures
  } = usePlayerStats();

  // Load player data (using mock data for now)
  useEffect(() => {
    // Simulate loading delay
    setTimeout(() => {
      setPlayers(mockFirebaseData);
      setLoading(false);
    }, 1000);
  }, []);

  // Filter players by status
  useEffect(() => {
    const filtered = players.filter(player => {
      if (statusFilter === 'All') return true;
      return player.notes === statusFilter;
    });
    setFilteredPlayers(filtered);
  }, [players, statusFilter]);

  // Calculate financial totals for authenticated users
  const calculateTotals = () => {
    if (!isAuthenticated || !filteredPlayers.length) return { total: 0, bonusesTotal: 0 };

    return filteredPlayers.reduce((totals, player) => ({
      total: totals.total + (parseFloat(player.overallTotal) || 0),
      bonusesTotal: totals.bonusesTotal + (parseFloat(player.bonuses) || 0)
    }), { total: 0, bonusesTotal: 0 });
  };

  const totals = calculateTotals();

  const handlePlayerClick = (player) => {
    console.log('Player clicked:', player.forename, player.surname);
    // We can add navigation later
  };

  // Status filter buttons
  const statusOptions = ['All', 'Squad', 'On loan', 'Loan in', 'Gone'];

  if (loading || statsLoading) {
    return (
      <div className="min-h-screen bg-gray-100 p-4">
        <div className="max-w-4xl mx-auto">
          <h1 className="text-3xl font-bold mb-6">Squad 2025/26</h1>
          <div className="text-center">Loading squad and statistics...</div>
        </div>
      </div>
    );
  }

  if (statsError) {
    return (
      <div className="min-h-screen bg-gray-100 p-4">
        <div className="max-w-4xl mx-auto">
          <h1 className="text-3xl font-bold mb-6">Squad 2025/26</h1>
          <div className="bg-yellow-100 border border-yellow-400 text-yellow-700 px-4 py-3 rounded">
            <strong>Warning:</strong> Could not load player statistics. {statsError}
            <br />
            <small>Player data will still be shown.</small>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-100 p-4">
      <div className="max-w-6xl mx-auto">
        <h1 className="text-3xl font-bold mb-6">Squad 2025/26</h1>

        {/* Statistics Summary */}
        <div className="bg-white rounded-lg shadow-md p-4 mb-6">
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-center">
            <div>
              <div className="text-2xl font-bold text-blue-600">{totalFixtures || 'Loading...'}</div>
              <div className="text-sm text-gray-600">Fixtures Played</div>
            </div>
            <div>
              <div className="text-2xl font-bold text-green-600">{playerStats.length || 'Loading...'}</div>
              <div className="text-sm text-gray-600">Players Used</div>
            </div>
            <div>
              <div className="text-2xl font-bold text-purple-600">{filteredPlayers.length}</div>
              <div className="text-sm text-gray-600">In Current View</div>
            </div>
            <div>
              <div className="text-2xl font-bold text-orange-600">
                {playerStats.filter(p => p.totalAppearances >= 10).length || 0}
              </div>
              <div className="text-sm text-gray-600">Regular Players (10+ apps)</div>
            </div>
          </div>
        </div>

        {/* Status Filter Buttons */}
        <div className="flex flex-wrap gap-2 mb-6">
          {statusOptions.map(status => (
            <button
              key={status}
              onClick={() => setStatusFilter(status)}
              className={`px-4 py-2 rounded-lg font-medium transition-colors ${
                statusFilter === status
                  ? 'bg-blue-600 text-white'
                  : 'bg-white text-gray-700 border border-gray-300 hover:bg-gray-50'
              }`}
            >
              {status}
            </button>
          ))}
        </div>

        {/* Financial Totals for Authenticated Users */}
        {isAuthenticated && (
          <div className="bg-green-50 border border-green-200 rounded-lg p-4 mb-6">
            <h3 className="font-semibold text-green-800 mb-2">Financial Summary ({statusFilter})</h3>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <strong>Overall Total: £{totals.total.toLocaleString()}</strong>
              </div>
              <div>
                <strong>Bonuses Total: £{totals.bonusesTotal.toLocaleString()}</strong>
              </div>
            </div>
          </div>
        )}

        {/* Players Grid */}
        <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
          {filteredPlayers.map(player => {
            const appearanceStats = getPlayerAppearanceSummary ? 
              getPlayerAppearanceSummary(player.forename + ' ' + player.surname) : 
              { total: 0, starts: 0, substitutes: 0, starterPercentage: 0 };

            const disciplinaryStats = getPlayerDisciplinarySummary ? 
              getPlayerDisciplinarySummary(player.forename + ' ' + player.surname) : 
              { yellow: 0, red: 0, total: 0 };

            return (
              <div
                key={player.id}
                onClick={() => handlePlayerClick(player)}
                className="bg-white rounded-lg shadow-md p-4 hover:shadow-lg transition-shadow cursor-pointer"
              >
                {/* Player Header */}
                <div className="mb-3">
                  <h3 className="text-lg font-semibold">
                    {player.forename} {player.surname}
                  </h3>
                  <p className="text-sm text-gray-600">
                    {player.notes} | Rating: {player.rating}/10
                  </p>
                </div>

                {/* Statistics Grid */}
                <div className="grid grid-cols-2 gap-3 text-sm">
                  {/* Goals */}
                  <div className="bg-blue-50 p-2 rounded">
                    <div className="font-medium text-blue-800">Goals</div>
                    <div className="text-lg font-bold text-blue-600">
                      {(player.goals || 0)}
                    </div>
                    <div className="text-xs text-gray-600">
                      L: {player.league || 0} | C: {(player.fACup || 0) + (player.eFLCup || 0) + (player.eFLTrophy || 0)}
                    </div>
                  </div>

                  {/* Appearances */}
                  <div className="bg-green-50 p-2 rounded">
                    <div className="font-medium text-green-800">Appearances</div>
                    <div className="text-lg font-bold text-green-600">
                      {appearanceStats.total}
                    </div>
                    <div className="text-xs text-gray-600">
                      {appearanceStats.starts}S / {appearanceStats.substitutes}Sub
                    </div>
                  </div>

                  {/* Starter % */}
                  <div className="bg-purple-50 p-2 rounded">
                    <div className="font-medium text-purple-800">Starter %</div>
                    <div className="text-lg font-bold text-purple-600">
                      {appearanceStats.starterPercentage}%
                    </div>
                    <div className="text-xs text-gray-600">
                      {appearanceStats.starts} starts
                    </div>
                  </div>

                  {/* Cards */}
                  <div className="bg-yellow-50 p-2 rounded">
                    <div className="font-medium text-yellow-800">Cards</div>
                    <div className="text-lg font-bold text-yellow-600">
                      {disciplinaryStats.total}
                    </div>
                    <div className="text-xs text-gray-600">
                      {disciplinaryStats.yellow}Y / {disciplinaryStats.red}R
                    </div>
                  </div>
                </div>

                {/* Financial Info (Authenticated Only) */}
                {isAuthenticated && (
                  <div className="mt-3 pt-3 border-t border-gray-200">
                    <div className="grid grid-cols-2 gap-2 text-sm">
                      <div>
                        <span className="font-medium">Weekly:</span> £{player.currentWeeklyWage?.toLocaleString() || '0'}
                      </div>
                      <div>
                        <span className="font-medium">Total:</span> £{player.overallTotal?.toLocaleString() || '0'}
                      </div>
                    </div>
                  </div>
                )}
              </div>
            );
          })}
        </div>

        {filteredPlayers.length === 0 && (
          <div className="text-center py-8">
            <p className="text-gray-500">No players found for the selected filter.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default EnhancedSquadList;
